// Merge all context: webhook body + setup vars + Graph token
const webhook = $('Webhook: Catering Lead').first().json;
const setup = $('Setup Variables').first().json;
const tokenResp = $input.first().json;

const body = webhook.body || webhook;
const leadId = body.inquiryId || `LEAD-${Date.now()}`;

// Build Azure OpenAI request for lead qualification
const systemPrompt = `You are a lead qualification assistant for Executive Catering CT, a corporate and event catering company in Connecticut.

Score this lead from 1-10 based on these factors:
- Budget vs guest count ratio (higher per-head budget = more serious)
- Event date proximity (within 30 days = urgent/serious, 30-90 days = good, 90+ = early stage)
- Corporate events score higher than personal events
- Having a venue secured indicates a more serious/advanced lead
- Non-profit events may have lower budgets but are valuable for community presence

Respond with JSON only:
{
  "qualificationScore": <1-10>,
  "qualificationNotes": "<2-3 sentence explanation of the score>",
  "suggestedMenuTier": "<Budget|Standard|Premium|Luxury>",
  "estimatedRevenue": "<dollar estimate based on guest count and budget range>",
  "urgency": "<high|medium|low>",
  "followUpRecommendation": "<specific next step for the sales team>"
}`;

const userPrompt = `Qualify this catering lead:

Name: ${body.firstName} ${body.lastName}
Email: ${body.email}
Phone: ${body.phone || 'Not provided'}
Company: ${body.company || 'Not provided'}
Non-Profit: ${body.isNonProfit || body.nonprofit || 'Unknown'}
Event Date: ${body.eventDate || 'Not specified'}
Has Venue: ${body.hasVenue || 'Unknown'}
Venue Name: ${body.venueName || 'N/A'}
Budget Range: ${body.budget || 'Not specified'}
Guest Count: ${body.guestCount || 'Not specified'}
Source: ${body.source || 'Website'}`;

return [{
  json: {
    ...setup,
    accessToken: tokenResp.access_token,
    lead: body,
    leadId,
    aoaiBody: {
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      max_completion_tokens: 1000,
      response_format: { type: 'json_object' }
    }
  }
}];

// Normalize phone to E.164 and build SMS welcome message
const lead = $('Parse & Prepare').first().json.lead;
const phone = (lead.phone || '').trim();

// Strip all non-digit characters
let digits = phone.replace(/[^0-9]/g, '');

// Normalize to E.164 for US numbers
let e164Phone = '';
if (digits.length === 10) {
  e164Phone = '+1' + digits;
} else if (digits.length === 11 && digits.startsWith('1')) {
  e164Phone = '+' + digits;
} else if (phone.startsWith('+') && digits.length >= 10) {
  e164Phone = '+' + digits;
}

// Validate: must be E.164 format with at least 11 digits
const isValid = /^\+[1-9]\d{10,14}$/.test(e164Phone);

// TRIAL MODE: Override To number to verified number only.
// Remove this line and use e164Phone directly when upgraded to paid.
const toNumber = '+19802190610';

// Build the welcome SMS body
const firstName = lead.firstName || 'there';
const smsBody = `Hi ${firstName}! Thanks for reaching out to Executive Catering CT. We've received your inquiry and are already working on a custom proposal for your event. Our team will be in touch within 24 hours. Questions? Reply to this text or call us anytime! - Executive Catering CT. Reply STOP to opt out.`;

// Twilio credentials from env (API Key auth)
const twilioSid = $env.TWILIO_ACCOUNT_SID || '';
const twilioApiKey = $env.TWILIO_API_KEY_SID || '';
const twilioApiSecret = $env.TWILIO_API_KEY_SECRET || '';
const twilioFrom = $env.TWILIO_PHONE_NUMBER || '';

// Build Basic Auth header (Base64 encode ApiKeySid:ApiKeySecret)
const twilioAuth = Buffer.from(twilioApiKey + ':' + twilioApiSecret).toString('base64');

return [{
  json: {
    phoneValid: isValid,
    e164Phone: toNumber,
    originalPhone: e164Phone,
    smsBody,
    twilioAccountSid: twilioSid,
    twilioAuth,
    twilioFromNumber: twilioFrom
  }
}];
